import type { Metadata, Viewport } from "next";
import type { ReactNode } from "react";
import "./globals.css";

export const metadata: Metadata = {
  title: {
    default: "Checkers Arena",
    template: "%s • Checkers Arena",
  },
  description:
    "A fast, fun, and polished checkers experience with responsive gameplay, social competition, and daily-play motivation.",
  applicationName: "Checkers Arena",
  keywords: [
    "checkers",
    "draughts",
    "board game",
    "strategy",
    "next.js",
    "game",
  ],
  authors: [{ name: "Checkers Arena Team" }],
  creator: "Checkers Arena Team",
  publisher: "Checkers Arena",
  robots: {
    index: true,
    follow: true,
  },
};

export const viewport: Viewport = {
  width: "device-width",
  initialScale: 1,
  maximumScale: 1,
  themeColor: [
    { media: "(prefers-color-scheme: light)", color: "#f6efe3" },
    { media: "(prefers-color-scheme: dark)", color: "#0f0f12" },
  ],
  colorScheme: "dark light",
};

type RootLayoutProps = {
  children: ReactNode;
};

export default function RootLayout({ children }: RootLayoutProps) {
  return (
    <html lang="en">
      <body className="app-root antialiased">
        <div className="app-shell">
          <a className="skip-link" href="#main-content">
            Skip to main content
          </a>

          <header className="app-header" role="banner">
            <div className="app-header__brand" aria-label="Checkers Arena">
              <span className="brand-mark" aria-hidden="true">
                ◈
              </span>
              <div className="brand-copy">
                <strong>Checkers Arena</strong>
                <span>Fast matches • satisfying strategy • daily progression</span>
              </div>
            </div>
          </header>

          <main id="main-content" className="app-main" role="main">
            {children}
          </main>

          <footer className="app-footer" role="contentinfo">
            <p>Built for quick rounds, focused strategy, and everyday replay value.</p>
          </footer>
        </div>
      </body>
    </html>
  );
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg: #f8f3e8;
  --bg-elevated: #fffaf1;
  --text: #1f1a17;
  --text-muted: #61544d;
  --border: #d9cbb9;
  --shadow: 0 16px 40px rgba(47, 30, 17, 0.12);

  --accent: #d14545;
  --accent-strong: #aa2525;
  --accent-contrast: #fff8f4;

  --board-light: #e6cba7;
  --board-dark: #8b5e3c;

  --radius-sm: 8px;
  --radius-md: 14px;
  --radius-lg: 20px;

  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-10: 2.5rem;
  --space-12: 3rem;

  --font-sans:
    Inter,
    "SF Pro Text",
    "Segoe UI",
    Roboto,
    "Helvetica Neue",
    Arial,
    "Noto Sans",
    sans-serif;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f0f12;
    --bg-elevated: #16171c;
    --text: #f3f4f6;
    --text-muted: #a7adb7;
    --border: #2b2f3a;
    --shadow: 0 20px 50px rgba(0, 0, 0, 0.35);

    --accent: #ff6a5f;
    --accent-strong: #ff867d;
    --accent-contrast: #1d1b1b;

    --board-light: #b28e69;
    --board-dark: #4a2f1f;
  }
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  min-height: 100%;
}

html {
  font-size: 16px;
  text-size-adjust: 100%;
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  color: var(--text);
  background:
    radial-gradient(1200px 800px at 0% -10%, rgba(209, 69, 69, 0.16), transparent 60%),
    radial-gradient(1000px 700px at 100% 0%, rgba(139, 94, 60, 0.12), transparent 62%),
    var(--bg);
  line-height: 1.5;
  letter-spacing: 0.01em;
}

a {
  color: inherit;
  text-decoration: none;
}

img,
svg,
video,
canvas {
  display: block;
  max-width: 100%;
}

button,
input,
textarea,
select {
  font: inherit;
  color: inherit;
}

:focus-visible {
  outline: 3px solid color-mix(in srgb, var(--accent) 70%, white 30%);
  outline-offset: 2px;
}

::selection {
  color: var(--accent-contrast);
  background: var(--accent);
}

.app-root {
  min-height: 100vh;
}

.app-shell {
  width: min(1200px, calc(100% - 2rem));
  margin-inline: auto;
  min-height: 100vh;
  display: grid;
  grid-template-rows: auto 1fr auto;
  gap: var(--space-6);
  padding: var(--space-6) 0 var(--space-8);
}

.skip-link {
  position: absolute;
  left: -9999px;
  top: 0;
  z-index: 1000;
  background: var(--accent);
  color: var(--accent-contrast);
  padding: var(--space-3) var(--space-4);
  border-radius: var(--radius-sm);
}

.skip-link:focus-visible {
  left: var(--space-4);
  top: var(--space-4);
}

.app-header,
.app-footer {
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  background: color-mix(in srgb, var(--bg-elevated) 88%, transparent 12%);
  box-shadow: var(--shadow);
  backdrop-filter: blur(8px);
}

.app-header {
  padding: var(--space-4) var(--space-6);
}

.app-header__brand {
  display: flex;
  align-items: center;
  gap: var(--space-4);
}

.brand-mark {
  display: inline-grid;
  place-items: center;
  width: 2.4rem;
  height: 2.4rem;
  border-radius: 999px;
  background: linear-gradient(135deg, var(--accent), var(--accent-strong));
  color: var(--accent-contrast);
  font-size: 1.1rem;
  box-shadow: 0 8px 24px rgba(209, 69, 69, 0.32);
}

.brand-copy {
  display: grid;
  gap: 2px;
}

.brand-copy strong {
  font-size: 1.025rem;
  line-height: 1.2;
}

.brand-copy span {
  font-size: 0.86rem;
  color: var(--text-muted);
}

.app-main {
  min-height: 0;
}

.app-footer {
  padding: var(--space-4) var(--space-6);
}

.app-footer p {
  margin: 0;
  color: var(--text-muted);
  font-size: 0.92rem;
}

.surface {
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  background: var(--bg-elevated);
  box-shadow: var(--shadow);
}

@media (max-width: 900px) {
  .app-shell {
    width: min(1200px, calc(100% - 1.25rem));
    gap: var(--space-4);
    padding-top: var(--space-4);
    padding-bottom: var(--space-6);
  }

  .app-header,
  .app-footer {
    border-radius: var(--radius-md);
  }

  .app-header,
  .app-footer {
    padding: var(--space-4);
  }

  .brand-copy span {
    font-size: 0.8rem;
  }
}

@media (max-width: 560px) {
  .app-shell {
    width: calc(100% - 1rem);
  }

  .app-header__brand {
    gap: var(--space-3);
  }

  .brand-mark {
    width: 2.1rem;
    height: 2.1rem;
    font-size: 1rem;
  }
}
